165: void UpstreamRequest::cleanUp() {
166:   if (cleaned_up_) {
167:     return;
168:   }
169:   cleaned_up_ = true;
170: 
171:   filter_manager_->destroyFilters();
172: 
173:   if (span_ != nullptr) {
174:     auto tracing_config = parent_.callbacks()->tracingConfig();
175:     ASSERT(tracing_config.has_value());
176:     Tracing::HttpTracerUtility::finalizeUpstreamSpan(*span_, stream_info_,
177:                                                      tracing_config.value().get());
178:   }
179: 
180:   if (per_try_timeout_ != nullptr) {
181:     // Allows for testing.
182:     per_try_timeout_->disableTimer();
183:   }
184: 
185:   if (per_try_idle_timeout_ != nullptr) {
186:     // Allows for testing.
187:     per_try_idle_timeout_->disableTimer();
188:   }
189: 
190:   if (max_stream_duration_timer_ != nullptr) {
191:     max_stream_duration_timer_->disableTimer();
192:   }
193: 
194:   if (upstream_log_flush_timer_ != nullptr) {
195:     upstream_log_flush_timer_->disableTimer();
196:   }
197: 
198:   clearRequestEncoder();
199: 
200:   // If desired, fire the per-try histogram when the UpstreamRequest
201:   // completes.
202:   if (record_timeout_budget_) {
203:     Event::Dispatcher& dispatcher = parent_.callbacks()->dispatcher();
204:     const MonotonicTime end_time = dispatcher.timeSource().monotonicTime();
205:     const std::chrono::milliseconds response_time =
206:         std::chrono::duration_cast<std::chrono::milliseconds>(end_time - start_time_);
207:     Upstream::ClusterTimeoutBudgetStatsOptRef tb_stats = parent_.cluster()->timeoutBudgetStats();
208:     tb_stats->get().upstream_rq_timeout_budget_per_try_percent_used_.recordValue(
209:         FilterUtility::percentageOfTimeout(response_time, parent_.timeout().per_try_timeout_));
210:   }
211: 
212:   // Ditto for request/response size histograms.
213:   Upstream::ClusterRequestResponseSizeStatsOptRef req_resp_stats_opt =
214:       parent_.cluster()->requestResponseSizeStats();
215:   if (req_resp_stats_opt.has_value() && parent_.downstreamHeaders()) {
216:     auto& req_resp_stats = req_resp_stats_opt->get();
217:     req_resp_stats.upstream_rq_headers_size_.recordValue(parent_.downstreamHeaders()->byteSize());
218:     req_resp_stats.upstream_rq_headers_count_.recordValue(parent_.downstreamHeaders()->size());
219:     req_resp_stats.upstream_rq_body_size_.recordValue(stream_info_.bytesSent());
220: 
221:     if (response_headers_size_.has_value()) {
222:       req_resp_stats.upstream_rs_headers_size_.recordValue(response_headers_size_.value());
223:       req_resp_stats.upstream_rs_headers_count_.recordValue(response_headers_count_.value());
224:       req_resp_stats.upstream_rs_body_size_.recordValue(stream_info_.bytesReceived());
225:     }
226:   }
227: 
228:   stream_info_.onRequestComplete();
229:   upstreamLog(AccessLog::AccessLogType::UpstreamEnd);
230: 
231:   while (downstream_data_disabled_ != 0) {
232:     parent_.callbacks()->onDecoderFilterBelowWriteBufferLowWatermark();
233:     parent_.cluster()->trafficStats()->upstream_flow_control_drained_total_.inc();
234:     --downstream_data_disabled_;
235:   }
236:   // The upstream HTTP filter chain callbacks own headers/trailers while they are traversing the
237:   // filter chain. Make sure to not delete them immediately when the stream ends, as the stream
238:   // often ends during filter chain processing and it causes use-after-free violations.
239:   parent_.callbacks()->dispatcher().deferredDelete(std::move(filter_manager_callbacks_));
240: }
